import requests

def get_weather(city: str) -> str:
    url = f"https://wttr.in/{city}?format=j1"
    try:
        response = requests.get(url)
        response.raise_for_status()
        data = response.json()
        current = data['current_condition'][0]
        desc = current['weatherDesc'][0]['value']
        temp = current['temp_C']
        return f"{city}当前天气：{desc}，气温{temp}摄氏度。"
    except Exception as e:
        return f"查询失败：{e}"

class WeatherAgent:
    def __init__(self):
        self.tools = {"get_weather": get_weather}

    def run(self, question: str) -> str:
        for city in ["北京", "上海", "广州", "深圳", "杭州"]:
            if city in question:
                return self.tools["get_weather"](city)
        return "我还不会回答这个问题，试着问我某个城市的天气？"

agent = WeatherAgent()
print(agent.run("今天上海天气怎么样？"))

class SimpleAgent:
    def __init__(self):
        self.memory = []
        self.tools = {}

    def perceive(self, observation):
        self.memory.append(observation)

    def think(self):
        # 这里将来会接入 LLM 进行推理
        return "调用工具查询信息"

    def act(self, tool_name, **kwargs):
        if tool_name in self.tools:
            return self.tools[tool_name](**kwargs)
        return "未知工具"

    def run(self, query):
        self.perceive(query)
        thought = self.think()
        result = self.act("search", q=query)
        self.perceive(result)
        return result

class ExpertSystem:
    """简化的专家系统推理引擎"""
    def __init__(self):
        self.rules = []  # (条件列表, 结论)
        self.facts = set()

    def add_rule(self, conditions, conclusion):
        self.rules.append((conditions, conclusion))

    def forward_chain(self):
        """正向链：从已知事实推导新结论"""
        changed = True
        while changed:
            changed = False
            for conditions, conclusion in self.rules:
                if all(c in self.facts for c in conditions):
                    if conclusion not in self.facts:
                        self.facts.add(conclusion)
                        changed = True
                        print(f"推导: {conclusion}")
        return self.facts

    def backward_chain(self, goal):
        """反向链：从目标出发寻找证据"""
        if goal in self.facts:
            return True
        for conditions, conclusion in self.rules:
            if conclusion == goal:
                if all(self.backward_chain(c) for c in conditions):
                    self.facts.add(goal)
                    return True
        return False

