import re
import random

# 规则库：模式 -> 响应模板列表
rules = [
    (r'I need (.*)', [
        "Why do you need {0}?",
        "Would it really help you to get {0}?"
    ]),
    (r'I am (.*)', [
        "Did you come to me because you are {0}?",
        "How long have you been {0}?"
    ]),
    (r'.* mother .*', [
        "Tell me more about your mother."
    ]),
    (r'.* father .*', [
        "Tell me more about your father."
    ]),
    (r'.*', [
        "Please tell me more.",
        "Can you elaborate on that?"
    ])
]

pronoun_swap = {
    "i": "you", "you": "i", "me": "you",
    "my": "your", "am": "are", "was": "were"
}

def swap_pronouns(phrase):
    words = phrase.lower().split()
    return " ".join(pronoun_swap.get(w, w) for w in words)

def respond(user_input):
    for pattern, responses in rules:
        match = re.search(pattern, user_input, re.IGNORECASE)
        if match:
            captured = match.group(1) if match.groups() else ''
            return random.choice(responses).format(
                swap_pronouns(captured))
    return random.choice(rules[-1][1])

